'use client';

/**
 * Chat Window Component
 * チャットウィンドウ全体（ヘッダー、メッセージ表示エリア、入力エリア）
 */

import { useChatUI } from '@/client/hooks/useChatUI';
import { ChatMessage, ChatLoadingIndicator } from './ChatMessage';
import { ChatInput } from './ChatInput';

interface ChatWindowProps {
  isOpen: boolean;
  onClose: () => void;
}

export function ChatWindow({ isOpen, onClose }: ChatWindowProps) {
  const {
    messages_i18n,
    messagesEndRef,
    messages,
    input,
    isLoading,
    error,
    reload,
    handleInputChange,
    handleFormSubmit,
  } = useChatUI();

  if (!isOpen) return null;

  return (
    <>
      {/* モバイル用オーバーレイ（768px未満） */}
      <div
        className="fixed inset-0 bg-black/50 z-[1000] md:hidden animate-fadeIn"
        onClick={onClose}
        aria-hidden="true"
      />

      {/* チャットウィンドウ */}
      <div
        className={`
          fixed z-[1001]
          flex flex-col
          bg-white
          shadow-2xl

          /* モバイル: 全画面表示 */
          bottom-0 left-0 right-0 top-0
          w-full h-full
          animate-slideUpMobile

          /* PC: 右下固定表示 */
          md:bottom-5 md:right-5 md:left-auto md:top-auto
          md:w-[400px] md:h-[600px]
          md:rounded-2xl
          md:animate-slideInDesktop
        `}
        role="dialog"
        aria-labelledby="chat-title"
        aria-modal="true"
      >
        {/* ヘッダー */}
        <div className="bg-[#E31E24] text-white px-4 py-3 md:py-4 flex items-center justify-between flex-shrink-0 md:rounded-t-2xl">
          <div className="flex items-center space-x-3">
            {/* WMGロゴ */}
            <div className="w-10 h-10 md:w-12 md:h-12 rounded-full bg-white flex items-center justify-center flex-shrink-0 p-1 overflow-hidden">
              <img
                src="/wmg2027-logo.png"
                alt="WMG2027 Logo"
                className="w-full h-full object-cover object-[center_65%]"
              />
            </div>

            {/* タイトル */}
            <div className="flex-1">
              <h2 id="chat-title" className="text-base md:text-lg font-bold leading-tight">
                WMG2027 サポートチャット
              </h2>
              <p className="text-xs md:text-sm text-white/95 leading-tight">
                お気軽にご質問ください
              </p>
            </div>
          </div>

          {/* 閉じるボタン */}
          <button
            onClick={onClose}
            className="w-8 h-8 md:w-9 md:h-9 flex items-center justify-center rounded-full hover:bg-white/20 transition-colors focus:outline-none focus:ring-2 focus:ring-white/50"
            aria-label="チャットを閉じる"
          >
            <svg
              xmlns="http://www.w3.org/2000/svg"
              fill="none"
              viewBox="0 0 24 24"
              strokeWidth={2.5}
              stroke="currentColor"
              className="w-6 h-6"
            >
              <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        {/* メッセージ表示エリア */}
        <div className="flex-1 overflow-y-auto bg-gray-50 px-4 py-4 md:px-4 md:py-4">
          {/* ウェルカムメッセージ */}
          {messages.length === 0 && (
            <div className="mb-4">
              <div className="flex justify-start items-start">
                {/* ボットアイコン（WMGロゴ） */}
                <div className="flex-shrink-0 w-8 h-8 md:w-10 md:h-10 rounded-full bg-white flex items-center justify-center mr-2 shadow-md p-1 overflow-hidden">
                  <img
                    src="/wmg2027-logo.png"
                    alt="WMG2027 Logo"
                    className="w-full h-full object-cover object-[center_65%]"
                  />
                </div>

                {/* メッセージ */}
                <div className="flex flex-col items-start max-w-[85%]">
                  <div className="bg-white text-gray-800 rounded-2xl px-4 py-3 shadow-[0_2px_8px_rgba(0,0,0,0.1)]">
                    <p className="text-sm md:text-[15px] whitespace-pre-wrap break-words leading-relaxed">
                      {messages_i18n.welcome}
                    </p>
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* メッセージリスト */}
          {messages.map(message => (
            <ChatMessage key={message.id} message={message} />
          ))}

          {/* ローディングインジケータ */}
          {isLoading && <ChatLoadingIndicator />}

          {/* エラー表示 */}
          {error && (
            <div className="bg-red-50 border border-red-200 text-red-800 p-3 rounded-lg mb-4">
              <p className="font-semibold">{messages_i18n.error}</p>
              <p className="text-sm mt-1">{error.message}</p>
              <button
                onClick={() => reload()}
                className="mt-2 text-sm underline hover:no-underline"
              >
                {messages_i18n.retry}
              </button>
            </div>
          )}

          <div ref={messagesEndRef} />
        </div>

        {/* 入力エリア */}
        <div className="flex-shrink-0">
          <ChatInput
            input={input}
            isLoading={isLoading}
            onInputChange={handleInputChange}
            onSubmit={handleFormSubmit}
          />
        </div>
      </div>
    </>
  );
}

