'use client';

/**
 * Chat Widget Component
 * 右下固定のチャットボタンとチャットウィンドウを統合したメインコンポーネント
 */

import { useState } from 'react';
import { ChatButton } from './ChatButton';
import { ChatWindow } from './ChatWindow';

export function ChatWidget() {
  const [isOpen, setIsOpen] = useState(false);

  const handleOpen = () => {
    setIsOpen(true);
  };

  const handleClose = () => {
    setIsOpen(false);
  };

  return (
    <>
      {/* チャットボタン（閉じている時のみ表示） */}
      {!isOpen && <ChatButton onClick={handleOpen} />}

      {/* チャットウィンドウ */}
      <ChatWindow isOpen={isOpen} onClose={handleClose} />
    </>
  );
}

'use client';

/**
 * Chat Widget Frame
 * タスク4.1: チャットUIシェルとストリーミング入出力
 */

import { useChatUI } from '@/client/hooks/useChatUI';
import { ChatMessage, ChatLoadingIndicator } from './ChatMessage';
import { ChatInput } from './ChatInput';
import { clientLogger } from '@/server/lib/logger';

export function ChatWidgetFrame() {
  const {
    messages_i18n,
    messagesEndRef,
    messages,
    input,
    isLoading,
    error,
    reload,
    handleInputChange,
    handleFormSubmit,
  } = useChatUI({
    onError: err => {
      clientLogger.error('Chat error', err);
    },
  });

  return (
    <div className="flex flex-col h-full bg-white rounded-none md:rounded-lg shadow-none md:shadow-lg">
      {/* ヘッダー */}
      <div className="bg-[#E31E24] text-white p-3 md:p-4 rounded-none md:rounded-t-lg relative">
        <div className="flex items-center justify-between">
          <div className="flex items-center space-x-3">
            {/* WMGロゴ */}
            <div className="w-10 h-10 md:w-12 md:h-12 rounded-full bg-white flex items-center justify-center flex-shrink-0 p-1 overflow-hidden">
              <img
                src="/wmg2027-logo.png"
                alt="WMG2027 Logo"
                className="w-full h-full object-cover object-[center_65%]"
              />
            </div>

            {/* タイトル */}
            <div className="flex-1">
              <h2 className="text-base md:text-lg font-bold leading-tight">
                WMG2027 サポートチャット
              </h2>
              <p className="text-xs md:text-sm text-white/95 leading-tight">
                お気軽にご質問ください
              </p>
            </div>
          </div>

          {/* 閉じるボタン */}
          <button
            className="w-8 h-8 md:w-9 md:h-9 flex items-center justify-center text-white hover:bg-white/20 rounded-full transition-colors flex-shrink-0"
            aria-label="閉じる"
          >
            <svg
              xmlns="http://www.w3.org/2000/svg"
              fill="none"
              viewBox="0 0 24 24"
              strokeWidth={2.5}
              stroke="currentColor"
              className="w-5 h-5 md:w-6 md:h-6"
            >
              <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>
      </div>

      {/* メッセージリスト */}
      <div className="flex-1 overflow-y-auto bg-gray-50 px-4 py-4 md:px-4 md:py-4">
        {/* ウェルカムメッセージ */}
        {messages.length === 0 && (
          <div className="mb-4">
            <div className="flex justify-start items-start">
              {/* ボットアイコン（WMGロゴ） */}
              <div className="flex-shrink-0 w-8 h-8 md:w-10 md:h-10 rounded-full bg-white flex items-center justify-center mr-2 shadow-md p-1 overflow-hidden">
                <img
                  src="/wmg2027-logo.png"
                  alt="WMG2027 Logo"
                  className="w-full h-full object-cover object-[center_65%]"
                />
              </div>

              {/* メッセージ */}
              <div className="flex flex-col items-start max-w-[85%]">
                <div className="bg-white text-gray-800 rounded-2xl px-4 py-3 shadow-[0_2px_8px_rgba(0,0,0,0.1)]">
                  <p className="text-sm md:text-[15px] whitespace-pre-wrap break-words leading-relaxed">
                    {messages_i18n.welcome}
                  </p>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* メッセージ表示（ChatMessageコンポーネントを使用） */}
        {messages.map(message => (
          <ChatMessage key={message.id} message={message} />
        ))}

        {/* ローディング表示（ChatLoadingIndicatorを使用） */}
        {isLoading && <ChatLoadingIndicator />}

        {/* エラー表示 */}
        {error && (
          <div className="bg-red-50 border border-red-200 text-red-800 p-3 rounded-lg mb-4">
            <p className="font-semibold">{messages_i18n.error}</p>
            <p className="text-sm mt-1">{error.message}</p>
            <button onClick={() => reload()} className="mt-2 text-sm underline hover:no-underline">
              {messages_i18n.retry}
            </button>
          </div>
        )}

        <div ref={messagesEndRef} />
      </div>

      {/* 入力エリア */}
      <div className="flex-shrink-0">
        <ChatInput
          input={input}
          isLoading={isLoading}
          onInputChange={handleInputChange}
          onSubmit={handleFormSubmit}
        />
      </div>
    </div>
  );
}

'use client';

/**
 * Chat Message Component
 * ユーザーとボットのメッセージ表示（Markdownサポート）
 */

import { Message } from 'ai';
import ReactMarkdown from 'react-markdown';

interface ChatMessageProps {
  message: Message;
}

export function ChatMessage({ message }: ChatMessageProps) {
  const isUser = message.role === 'user';
  const timestamp = new Date().toLocaleTimeString('ja-JP', {
    hour: '2-digit',
    minute: '2-digit',
  });

  if (isUser) {
    return (
      <div className="flex justify-end items-end mb-4 animate-slideIn">
        <div className="flex flex-col items-end max-w-[75%] md:max-w-[70%] sm:max-w-[80%]">
          <div className="bg-[#FFF0F0] text-[#333333] rounded-2xl rounded-br-md px-4 py-3">
            <p className="text-sm md:text-[15px] whitespace-pre-wrap break-words leading-relaxed">
              {message.content}
            </p>
          </div>
          <span className="text-xs text-gray-400 mt-1 px-1">{timestamp}</span>
        </div>
      </div>
    );
  }

  return (
    <div className="flex justify-start items-start mb-4 animate-slideIn">
      {/* ボットアイコン（WMGロゴ） */}
      <div className="flex-shrink-0 w-8 h-8 md:w-10 md:h-10 rounded-full bg-white flex items-center justify-center mr-2 shadow-md p-1 overflow-hidden">
        <img
          src="/wmg2027-logo.png"
          alt="WMG2027 Logo"
          className="w-full h-full object-cover object-[center_65%]"
        />
      </div>

      {/* メッセージ（Markdownレンダリング） */}
      <div className="flex flex-col items-start max-w-[75%] md:max-w-[70%] sm:max-w-[80%]">
        <div className="bg-white text-[#333333] rounded-2xl px-4 py-3 shadow-[0_2px_8px_rgba(0,0,0,0.1)]">
          <div className="text-sm md:text-[15px] leading-relaxed prose prose-sm max-w-none prose-a:text-blue-600 prose-a:underline hover:prose-a:text-blue-800">
            <ReactMarkdown
              components={{
                a: ({ href, children }) => (
                  <a
                    href={href}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="text-blue-600 underline hover:text-blue-800"
                  >
                    {children}
                  </a>
                ),
                p: ({ children }) => <p className="mb-2 last:mb-0">{children}</p>,
                ul: ({ children }) => <ul className="list-disc list-inside mb-2">{children}</ul>,
